__global__ void
srad_kernel_1(
          float *E_C, 
          float *W_C, 
          float *N_C, 
          float *S_C,
          float * J_cuda, 
          float * C_cuda, 
          int cols, 
          int rows, 
          float q0sqr
) 
{
  int bx = get_block_id(0);
  int by = get_block_id(1);
  int tx = get_thread_id(0);
  int ty = get_thread_id(1);

  int index   = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * ty + tx;

  float n, w, e, s, jc, g2, l, num, den, qsqr, c;

  __shared__ float temp[BLOCK_SIZE][BLOCK_SIZE];
  __shared__ float temp_result[BLOCK_SIZE][BLOCK_SIZE];

  __shared__ float north[BLOCK_SIZE][BLOCK_SIZE];
  __shared__ float south[BLOCK_SIZE][BLOCK_SIZE];
  __shared__ float  east[BLOCK_SIZE][BLOCK_SIZE];
  __shared__ float  west[BLOCK_SIZE][BLOCK_SIZE];

  // Load central value
  if (index < cols * rows) {
      temp[ty][tx] = J_cuda[index];
  } else {
      temp[ty][tx] = 0.0f;
  }
  __syncthreads();

  jc = temp[ty][tx];

  // Calculate neighbor indices carefully to avoid out-of-bounds reads if possible, 
  // but the original logic relies on specific wrapping/fallback for boundaries.
  // We implement the boundary checks explicitly.

  int idx_n = index - cols;
  int idx_s = index + cols;
  int idx_w = index - 1;
  int idx_e = index + 1;

  // Load North
  if (by == 0 && ty == 0) {
      // Top edge of grid: wrap to itself or specific row as per original CUDA code
      // Original: if (0 == by) north = J_cuda[BLOCK_SIZE * bx + tx];
      int wrap_idx = BLOCK_SIZE * bx + tx;
      if (wrap_idx < cols * rows) north[ty][tx] = J_cuda[wrap_idx];
      else north[ty][tx] = jc;
  } else {
      if (idx_n >= 0 && idx_n < cols * rows) north[ty][tx] = J_cuda[idx_n];
      else north[ty][tx] = jc;
  }

  // Load South
  if (by == get_num_blocks(1) - 1 && ty == BLOCK_SIZE - 1) {
      // Bottom edge
      int wrap_idx = cols * BLOCK_SIZE * (get_num_blocks(1) - 1) + BLOCK_SIZE * bx + cols * (BLOCK_SIZE - 1) + tx;
      if (wrap_idx < cols * rows) south[ty][tx] = J_cuda[wrap_idx];
      else south[ty][tx] = jc;
  } else {
      if (idx_s < cols * rows) south[ty][tx] = J_cuda[idx_s];
      else south[ty][tx] = jc;
  }

  // Load West
  if (bx == 0 && tx == 0) {
      // Left edge
      int wrap_idx = cols * BLOCK_SIZE * by + cols * ty;
      if (wrap_idx < cols * rows) west[ty][tx] = J_cuda[wrap_idx];
      else west[ty][tx] = jc;
  } else {
      if (idx_w >= 0 && idx_w < cols * rows) west[ty][tx] = J_cuda[idx_w];
      else west[ty][tx] = jc;
  }

  // Load East
  if (bx == get_num_blocks(0) - 1 && tx == BLOCK_SIZE - 1) {
      // Right edge
      int wrap_idx = cols * BLOCK_SIZE * by + BLOCK_SIZE * (get_num_blocks(0) - 1) + cols * ty + BLOCK_SIZE - 1;
      if (wrap_idx < cols * rows) east[ty][tx] = J_cuda[wrap_idx];
      else east[ty][tx] = jc;
  } else {
      if (idx_e < cols * rows) east[ty][tx] = J_cuda[idx_e];
      else east[ty][tx] = jc;
  }

  __syncthreads();

  // Determine differences based on position
  if (0 == ty && 0 == tx) { 
      n  = north[ty][tx] - jc;
      s  = temp[ty+1][tx] - jc;
      w  = west[ty][tx]  - jc; 
      e  = temp[ty][tx+1] - jc;
  }	    
  else if (ty == 0 && tx == BLOCK_SIZE-1) { 
      n  = north[ty][tx] - jc;
      s  = temp[ty+1][tx] - jc;
      w  = temp[ty][tx-1] - jc; 
      e  = east[ty][tx] - jc;
  }
  else if (ty == BLOCK_SIZE -1 && tx == BLOCK_SIZE - 1) { 
      n  = temp[ty-1][tx] - jc;
      s  = south[ty][tx] - jc;
      w  = temp[ty][tx-1] - jc; 
      e  = east[ty][tx]  - jc;
  }
  else if (ty == BLOCK_SIZE -1 && tx == 0) {
      n  = temp[ty-1][tx] - jc;
      s  = south[ty][tx] - jc;
      w  = west[ty][tx]  - jc; 
      e  = temp[ty][tx+1] - jc;
  }
  else if (0 == ty) { 
      n  = north[ty][tx] - jc;
      s  = temp[ty+1][tx] - jc;
      w  = temp[ty][tx-1] - jc; 
      e  = temp[ty][tx+1] - jc;
  }
  else if (tx == BLOCK_SIZE -1) { 
      n  = temp[ty-1][tx] - jc;
      s  = temp[ty+1][tx] - jc;
      w  = temp[ty][tx-1] - jc; 
      e  = east[ty][tx] - jc;
  }
  else if (ty == BLOCK_SIZE -1) { 
      n  = temp[ty-1][tx] - jc;
      s  = south[ty][tx] - jc;
      w  = temp[ty][tx-1] - jc; 
      e  = temp[ty][tx+1] - jc;
  }
  else if (0 == tx) { 
      n  = temp[ty-1][tx] - jc;
      s  = temp[ty+1][tx] - jc;
      w  = west[ty][tx] - jc; 
      e  = temp[ty][tx+1] - jc;
  }
  else {  
      n  = temp[ty-1][tx] - jc;
      s  = temp[ty+1][tx] - jc;
      w  = temp[ty][tx-1] - jc; 
      e  = temp[ty][tx+1] - jc;
  }

  if (jc == 0.0f) {
      g2 = 0.0f;
      l = 0.0f;
  } else {
      g2 = ( n * n + s * s + w * w + e * e ) / (jc * jc);
      l = ( n + s + w + e ) / jc;
  }

  num  = (0.5*g2) - ((1.0/16.0)*(l*l));
  den  = 1.0f + (0.25f*l);

  if (den == 0.0f) qsqr = 0.0f;
  else qsqr = num/(den*den);

  float denom_q = q0sqr * (1.0f + q0sqr);
  if (denom_q == 0.0f) den = 0.0f;
  else den = (qsqr - q0sqr) / denom_q;

  c = 1.0f / (1.0f + den);

  if (c < 0.0f) temp_result[ty][tx] = 0.0f;
  else if (c > 1.0f) temp_result[ty][tx] = 1.0f;
  else temp_result[ty][tx] = c;

  __syncthreads();

  if (index < cols * rows) {
      C_cuda[index] = temp_result[ty][tx];
      E_C[index] = e;
      W_C[index] = w;
      S_C[index] = s;
      N_C[index] = n;
  }
}

__global__ void
srad_kernel_2(
          float *E_C, 
          float *W_C, 
          float *N_C, 
          float *S_C,	
          float * J_cuda, 
          float * C_cuda, 
          int cols, 
          int rows, 
          float lambda,
          float q0sqr
) 
{
  int bx = get_block_id(0);
  int by = get_block_id(1);
  int tx = get_thread_id(0);
  int ty = get_thread_id(1);

  int index   = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * ty + tx;

  float cc, cn, cs, ce, cw, d_sum;

  __shared__ float south_c[BLOCK_SIZE][BLOCK_SIZE];
  __shared__ float  east_c[BLOCK_SIZE][BLOCK_SIZE];
  __shared__ float c_cuda_temp[BLOCK_SIZE][BLOCK_SIZE];
  __shared__ float c_cuda_result[BLOCK_SIZE][BLOCK_SIZE];
  __shared__ float temp[BLOCK_SIZE][BLOCK_SIZE];

  if (index < cols * rows) temp[ty][tx] = J_cuda[index];
  else temp[ty][tx] = 0.0f;
  __syncthreads();

  int idx_s = index + cols;
  int idx_e = index + 1;

  // Load South C
  if (by == get_num_blocks(1) - 1 && ty == BLOCK_SIZE - 1) {
      int wrap_idx = cols * BLOCK_SIZE * (get_num_blocks(1) - 1) + BLOCK_SIZE * bx + cols * (BLOCK_SIZE - 1) + tx;
      if (wrap_idx < cols * rows) south_c[ty][tx] = C_cuda[wrap_idx];
      else south_c[ty][tx] = 0.0f;
  } else {
      if (idx_s < cols * rows) south_c[ty][tx] = C_cuda[idx_s];
      else south_c[ty][tx] = 0.0f;
  }
  __syncthreads();

  // Load East C
  if (bx == get_num_blocks(0) - 1 && tx == BLOCK_SIZE - 1) {
      int wrap_idx = cols * BLOCK_SIZE * by + BLOCK_SIZE * (get_num_blocks(0) - 1) + cols * ty + BLOCK_SIZE - 1;
      if (wrap_idx < cols * rows) east_c[ty][tx] = C_cuda[wrap_idx];
      else east_c[ty][tx] = 0.0f;
  } else {
      if (idx_e < cols * rows) east_c[ty][tx] = C_cuda[idx_e];
      else east_c[ty][tx] = 0.0f;
  }
  __syncthreads();

  if (index < cols * rows) c_cuda_temp[ty][tx] = C_cuda[index];
  else c_cuda_temp[ty][tx] = 0.0f;
  __syncthreads();

  cc = c_cuda_temp[ty][tx];

  if (ty == BLOCK_SIZE -1 && tx == BLOCK_SIZE - 1) { 
      cn  = cc;
      cs  = south_c[ty][tx];
      cw  = cc; 
      ce  = east_c[ty][tx];
  } 
  else if (tx == BLOCK_SIZE -1) { 
      cn  = cc;
      cs  = c_cuda_temp[ty+1][tx];
      cw  = cc; 
      ce  = east_c[ty][tx];
  }
  else if (ty == BLOCK_SIZE -1) { 
      cn  = cc;
      cs  = south_c[ty][tx];
      cw  = cc; 
      ce  = c_cuda_temp[ty][tx+1];
  }
  else { 
      cn  = cc;
      cs  = c_cuda_temp[ty+1][tx];
      cw  = cc; 
      ce  = c_cuda_temp[ty][tx+1];
  }

  d_sum = cn * N_C[index] + cs * S_C[index] + cw * W_C[index] + ce * E_C[index];

  c_cuda_result[ty][tx] = temp[ty][tx] + 0.25f * lambda * d_sum;

  __syncthreads();

  if (index < cols * rows) {
      J_cuda[index] = c_cuda_result[ty][tx];
  }
}
